     6→// ============ SMART SCHEDULING ============
     7→
     8→/**
     9→ * Suggest optimal interview slots based on recruiter preferences and candidate availability
    10→ */
    11→async function suggestSlots(recruiterId, candidateTimezone = 'America/New_York', options = {}) {
    12→  const { daysAhead = 7, slotsCount = 6, durationMinutes = 60 } = options;
    13→
    14→  // Get recruiter preferences
    15→  let prefs;
    16→  const prefsResult = await pool.query(
    17→    'SELECT * FROM scheduling_preferences WHERE user_id = $1',
    18→    [recruiterId]
    19→  );
    20→
    21→  if (prefsResult.rows.length > 0) {
    22→    prefs = prefsResult.rows[0];
    23→  } else {
    24→    prefs = {
    25→      timezone: 'America/New_York',
    26→      available_days: ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'],
    27→      available_hours: { start: '09:00', end: '17:00' },
    28→      buffer_minutes: 15,
    29→      preferred_duration: 60,
    30→      blackout_dates: []
    31→    };
    32→  }
    33→
    34→  const duration = durationMinutes || prefs.preferred_duration || 60;
    35→  const buffer = prefs.buffer_minutes || 15;
    36→  const availDays = Array.isArray(prefs.available_days) ? prefs.available_days : ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'];
    37→  const hours = prefs.available_hours || { start: '09:00', end: '17:00' };
    38→  const blackoutDates = Array.isArray(prefs.blackout_dates) ? prefs.blackout_dates : [];
    39→
    40→  // Get existing scheduled interviews for conflict detection
    41→  const existingInterviews = await pool.query(
    42→    `SELECT scheduled_at, duration_minutes FROM scheduled_interviews
    43→     WHERE recruiter_id = $1 AND status IN ('scheduled', 'confirmed')
    44→     AND scheduled_at > NOW() AND scheduled_at < NOW() + INTERVAL '${Math.min(daysAhead, 30)} days'`,
    45→    [recruiterId]
    46→  );
    47→
    48→  const busySlots = existingInterviews.rows.map(r => ({
    49→    start: new Date(r.scheduled_at),
    50→    end: new Date(new Date(r.scheduled_at).getTime() + (r.duration_minutes || 60) * 60000)
    51→  }));
    52→
    53→  // Generate available slots
    54→  const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
    55→  const slots = [];
    56→  const now = new Date();
    57→
    58→  for (let d = 1; d <= daysAhead && slots.length < slotsCount; d++) {
    59→    const date = new Date(now);
    60→    date.setDate(date.getDate() + d);
    61→    const dayName = dayNames[date.getDay()];
    62→
    63→    // Skip unavailable days
    64→    if (!availDays.includes(dayName)) continue;
    65→
    66→    // Skip blackout dates
    67→    const dateStr = date.toISOString().split('T')[0];
    68→    if (blackoutDates.includes(dateStr)) continue;
    69→
    70→    // Parse available hours
    71→    const [startH, startM] = hours.start.split(':').map(Number);
    72→    const [endH, endM] = hours.end.split(':').map(Number);
    73→
    74→    // Generate slots every (duration + buffer) minutes
    75→    const slotStep = duration + buffer;
    76→    for (let h = startH; h < endH && slots.length < slotsCount; h++) {
    77→      for (let m = (h === startH ? startM : 0); m < 60 && slots.length < slotsCount; m += slotStep) {
    78→        // Check if slot fits before end time
    79→        const slotEnd = h * 60 + m + duration;
    80→        if (slotEnd > endH * 60 + endM) break;
    81→
    82→        const slotStart = new Date(date);
    83→        slotStart.setHours(h, m, 0, 0);
    84→
    85→        // Skip past slots
    86→        if (slotStart <= now) continue;
    87→
    88→        // Check for conflicts
    89→        const hasConflict = busySlots.some(busy => {
    90→          const bufferedStart = new Date(busy.start.getTime() - buffer * 60000);
    91→          const bufferedEnd = new Date(busy.end.getTime() + buffer * 60000);
    92→          return slotStart >= bufferedStart && slotStart < bufferedEnd;
    93→        });
    94→
    95→        if (!hasConflict) {
    96→          slots.push({
    97→            start: slotStart.toISOString(),
    98→            end: new Date(slotStart.getTime() + duration * 60000).toISOString(),
    99→            duration_minutes: duration,
   100→            day: dayName,
   101→            date: dateStr,
   102→            recruiter_timezone: prefs.timezone,
   103→            candidate_timezone: candidateTimezone
   104→          });
   105→        }
   106→      }
   107→    }
   108→  }
   109→
   110→  return slots;
   111→}
