   113→/**
   114→ * Create reminders for a scheduled interview
   115→ */
   116→async function createReminders(interviewId, candidateId, recruiterId, scheduledAt) {
   117→  const time = new Date(scheduledAt);
   118→
   119→  // 1 day before
   120→  const dayBefore = new Date(time.getTime() - 24 * 60 * 60000);
   121→  // 1 hour before
   122→  const hourBefore = new Date(time.getTime() - 60 * 60000);
   123→
   124→  const reminders = [];
   125→
   126→  // Only create future reminders
   127→  const now = new Date();
   128→  if (dayBefore > now) {
   129→    reminders.push(
   130→      { interview_id: interviewId, recipient_id: candidateId, reminder_type: '1_day_before', send_at: dayBefore },
   131→      { interview_id: interviewId, recipient_id: recruiterId, reminder_type: '1_day_before', send_at: dayBefore }
   132→    );
   133→  }
   134→  if (hourBefore > now) {
   135→    reminders.push(
   136→      { interview_id: interviewId, recipient_id: candidateId, reminder_type: '1_hour_before', send_at: hourBefore },
   137→      { interview_id: interviewId, recipient_id: recruiterId, reminder_type: '1_hour_before', send_at: hourBefore }
   138→    );
   139→  }
   140→
   141→  for (const r of reminders) {
   142→    await pool.query(
   143→      `INSERT INTO interview_reminders (interview_id, recipient_id, reminder_type, send_at)
   144→       VALUES ($1, $2, $3, $4)`,
   145→      [r.interview_id, r.recipient_id, r.reminder_type, r.send_at]
   146→    );
