   171→async function generateScreeningQuestions(jobTitle, jobDescription, options = {}) {
   172→  const aiProvider = require('../lib/ai-provider');
   173→
   174→  const prompt = `Generate 6-8 screening interview questions for a "${jobTitle}" position.
