   209→    { question_text: 'Describe a challenging project you led or contributed to significantly. What was your approach?', question_type: 'behavioral', difficulty: 'medium', evaluation_criteria: ['Problem-solving', 'Leadership', 'Technical depth', 'Impact'], time_limit_seconds: 150 },
