   236→
   237→${qaContext}
   238→
   239→Return ONLY valid JSON with this structure:
   240→{
   241→  "question_scores": [
   242→    {"question_index": 0, "score": 0-100, "feedback": "brief assessment"}
   243→  ],
   244→  "communication_clarity": {"score": 0-100, "feedback": "assessment"},
   245→  "technical_depth": {"score": 0-100, "feedback": "assessment"},
   246→  "confidence_enthusiasm": {"score": 0-100, "indicators": ["list of observed indicators"]},
   247→  "red_flags": ["list any inconsistencies, evasiveness, or concerns"],
