      success: true,
      evaluations: evaluations.rows,
      composite: composite.rows[0] || null
    });
  } catch (err) {
    console.error('Get AI scores error:', err);
    res.status(500).json({ error: 'Failed to fetch AI scores' });
  }
});

module.exports = router;

